Greedy insertion with simulated cost delta evaluation across all existing non-empty routes plus a dedicated empty route per order, selecting the minimal cost increase while preserving feasibility.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	snapshotCosts := make([]float64, MAXASSIGNS)
	snapshotLens := make([]int, MAXASSIGNS)
	for i := 0; i < MAXASSIGNS; i++ {
		snapshotCosts[i] = dispatch.Assigns[i].Cost
		snapshotLens[i] = 0
	}
	for i := 0; i < dispatch.AssignsLen; i++ {
		snapshotLens[i] = dispatch.Assigns[i].StationsLen
	}
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestCand := candidate{-1, 0, false}
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := snapshotCosts[ii]
			ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				delta := newCost - oldCost
				if delta >= 0 || (!bestCand.ok) || (delta < bestCand.costDelta) {
					bestCand.assignIdx = ii
					bestCand.costDelta = delta
					bestCand.ok = true
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
				snapshotCosts[ii] = oldCost
			}
		}
		if bestCand.ok {
			dispatch.Assigns[bestCand.assignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestCand.assignIdx].GenRoute()
			snapshotCosts[bestCand.assignIdx] = dispatch.Assigns[bestCand.assignIdx].Cost
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[idx].GenRoute()
				snapshotCosts[idx] = dispatch.Assigns[idx].Cost
				snapshotLens[idx] = 2
				dispatch.AssignsLen++
			} else {
				fallbackOk := false
				for ii := 0; ii < dispatch.AssignsLen && !fallbackOk; ii++ {
					oldCost := snapshotCosts[ii]
					ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
					if ok {
						dispatch.Assigns[ii].GenRoute()
						newCost := dispatch.Assigns[ii].Cost
						if newCost >= 0 {
							fallbackOk = true
							snapshotCosts[ii] = newCost
							break
						}
						dispatch.Assigns[ii].RemoveShip(total_ship + jj)
						dispatch.Assigns[ii].GenRoute()
						snapshotCosts[ii] = oldCost
					}
				}
				if !fallbackOk && dispatch.AssignsLen > 0 {
					dispatch.Assigns[0].AddShip(total_ship+jj, oris[jj], dess[jj])
					dispatch.Assigns[0].GenRoute()
					snapshotCosts[0] = dispatch.Assigns[0].Cost
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

